INSERT INTO content_pages (content_key, page_kind, subject_id, topic_id, chapter_id, worksheet_id, title, source_format, source_path, content_json, content_hash) VALUES ('chapter:math:terme-gleichungen:terme-umformen', 'chapter', 'math', 'terme-gleichungen', 'terme-umformen', NULL, 'Terme umformen', 'md', 'content/base/math/terme-gleichungen/00-terme-umformen/overview.md', '{"title":"Terme umformen","content":[{"header":"Zusammenfassen","content":[{"markdown":"Terme mit gleichen Variablen und gleichen Exponenten können zusammengefasst werden."},{"type":"card","kind":"highlight","content":{"markdown":"$3x + 5x = 8x$\n\n$2a^2 - a^2 + 4a = a^2 + 4a$"}},{"type":"callout","content":{"markdown":"Nur gleichartige Terme dürfen zusammengefasst werden. $3x$ und $3x^2$ sind **nicht** gleichartig."}}]},{"header":"Ausmultiplizieren","content":[{"markdown":"Beim Ausmultiplizieren wenden wir das Distributivgesetz an."},{"type":"card","kind":"highlight","content":{"markdown":"$a \\cdot (b + c) = a \\cdot b + a \\cdot c$"}},{"type":"card","kind":"concept","content":{"markdown":"$3 \\cdot (x + 5) = 3x + 15$\n\n$-2 \\cdot (x - 4) = -2x + 8$"}},{"type":"callout","content":{"markdown":"Achtung bei negativem Vorzeichen vor der Klammer: Das Minuszeichen ändert das Vorzeichen **jedes** Summanden."}}]},{"header":"Ausklammern","content":[{"markdown":"Ausklammern ist die Umkehrung des Ausmultiplizierens. Wir suchen den größten gemeinsamen Faktor aller Summanden."},{"type":"card","kind":"highlight","content":{"markdown":"$a \\cdot b + a \\cdot c = a \\cdot (b + c)$"}},{"type":"card","kind":"concept","content":{"markdown":"$6x^2 + 4x = 2x \\cdot (3x + 2)$\n\n$x^2 - x = x \\cdot (x - 1)$"}}]},{"header":"Äquivalente Terme","content":[{"markdown":"Zwei Terme sind äquivalent, wenn sie für alle Variablenwerte denselben Wert liefern."},{"type":"card","kind":"concept","content":{"markdown":"$2(x + 3)$ und $2x + 6$ sind äquivalent.\n\nDas lässt sich durch Ausmultiplizieren zeigen: $2(x + 3) = 2x + 6$."}}]}]}'::jsonb, 'fc427c4afc501cc0909284d3fe1e9cf315a5b1ea6118d90006d789c2819007ff') ON CONFLICT (content_key) DO UPDATE SET page_kind = EXCLUDED.page_kind, subject_id = EXCLUDED.subject_id, topic_id = EXCLUDED.topic_id, chapter_id = EXCLUDED.chapter_id, worksheet_id = EXCLUDED.worksheet_id, title = EXCLUDED.title, source_format = EXCLUDED.source_format, source_path = EXCLUDED.source_path, content_json = EXCLUDED.content_json, content_hash = EXCLUDED.content_hash, updated_at = NOW();
INSERT INTO content_pages (content_key, page_kind, subject_id, topic_id, chapter_id, worksheet_id, title, source_format, source_path, content_json, content_hash) VALUES ('chapter:math:terme-gleichungen:binomische-formeln', 'chapter', 'math', 'terme-gleichungen', 'binomische-formeln', NULL, 'Binomische Formeln', 'md', 'content/base/math/terme-gleichungen/10-binomische-formeln/overview.md', '{"title":"Binomische Formeln","content":[{"header":"Die drei binomischen Formeln","content":[{"type":"card","kind":"highlight","content":{"markdown":"1. $(a + b)^2 = a^2 + 2ab + b^2$\n\n2. $(a - b)^2 = a^2 - 2ab + b^2$\n\n3. $(a + b)(a - b) = a^2 - b^2$"}}]},{"header":"Anwenden: Ausmultiplizieren","content":[{"markdown":"Wir erkennen das Muster und setzen die Terme für $a$ und $b$ ein."},{"type":"card","kind":"concept","content":{"markdown":"$(x + 3)^2 = x^2 + 2 \\cdot x \\cdot 3 + 9 = x^2 + 6x + 9$\n\n$(2x - 1)^2 = 4x^2 - 4x + 1$\n\n$(x + 5)(x - 5) = x^2 - 25$"}}]},{"header":"Anwenden: Faktorisieren","content":[{"markdown":"Erkennen wir eine binomische Struktur in einem Term, können wir rückwärts faktorisieren."},{"type":"card","kind":"concept","content":{"markdown":"$x^2 + 8x + 16 = (x + 4)^2$\n\n$9x^2 - 1 = (3x + 1)(3x - 1)$"}},{"type":"callout","content":{"markdown":"Bei der 1. und 2. Formel: Der mittlere Term ist immer $\\pm 2ab$. Das hilft beim Erkennen."}}]},{"header":"Merkhilfe","content":[{"type":"table","headers":[{"markdown":"Formel"},{"markdown":"Erkennungsmerkmal"}],"rows":[[{"markdown":"$(a+b)^2$"},{"markdown":"Alle Vorzeichen positiv"}],[{"markdown":"$(a-b)^2$"},{"markdown":"Erster und letzter Term positiv, mittlerer negativ"}],[{"markdown":"$(a+b)(a-b)$"},{"markdown":"Zwei Quadrate mit Differenz, kein mittlerer Term"}]]}]}]}'::jsonb, 'ad09d19b6ed072500109091f41b6d12c657a029d9a6b977fcd5e2158353359ec') ON CONFLICT (content_key) DO UPDATE SET page_kind = EXCLUDED.page_kind, subject_id = EXCLUDED.subject_id, topic_id = EXCLUDED.topic_id, chapter_id = EXCLUDED.chapter_id, worksheet_id = EXCLUDED.worksheet_id, title = EXCLUDED.title, source_format = EXCLUDED.source_format, source_path = EXCLUDED.source_path, content_json = EXCLUDED.content_json, content_hash = EXCLUDED.content_hash, updated_at = NOW();
INSERT INTO content_pages (content_key, page_kind, subject_id, topic_id, chapter_id, worksheet_id, title, source_format, source_path, content_json, content_hash) VALUES ('chapter:math:terme-gleichungen:bruchrechnung', 'chapter', 'math', 'terme-gleichungen', 'bruchrechnung', NULL, 'Bruchrechnung', 'md', 'content/base/math/terme-gleichungen/20-bruchrechnung/overview.md', '{"title":"Bruchrechnung","content":[{"header":"Kürzen und Erweitern","content":[{"type":"card","kind":"highlight","content":{"markdown":"$\\frac{a \\cdot k}{b \\cdot k} = \\frac{a}{b}$ (Kürzen)\n\n$\\frac{a}{b} = \\frac{a \\cdot k}{b \\cdot k}$ (Erweitern)"}},{"type":"card","kind":"concept","content":{"markdown":"$\\frac{6x^2}{4x} = \\frac{3x}{2}$"}}]},{"header":"Addition und Subtraktion","content":[{"markdown":"Brüche können nur addiert und subtrahiert werden, wenn sie denselben Nenner haben."},{"type":"card","kind":"highlight","content":{"markdown":"$\\frac{a}{c} + \\frac{b}{c} = \\frac{a + b}{c}$"}},{"type":"card","kind":"concept","content":{"markdown":"$\\frac{1}{3} + \\frac{1}{4} = \\frac{4}{12} + \\frac{3}{12} = \\frac{7}{12}$\n\n$\\frac{x}{x+1} - \\frac{2}{x+1} = \\frac{x - 2}{x+1}$"}}]},{"header":"Multiplikation und Division","content":[{"markdown":"Bei der Multiplikation multiplizieren wir Zähler mit Zähler und Nenner mit Nenner."},{"type":"card","kind":"highlight","content":{"markdown":"$\\frac{a}{b} \\cdot \\frac{c}{d} = \\frac{a \\cdot c}{b \\cdot d}$\n\n$\\frac{a}{b} \\div \\frac{c}{d} = \\frac{a}{b} \\cdot \\frac{d}{c} = \\frac{a \\cdot d}{b \\cdot c}$"}},{"type":"card","kind":"concept","content":{"markdown":"$\\frac{2}{3} \\cdot \\frac{5}{7} = \\frac{10}{21}$\n\n$\\frac{x}{2} \\div \\frac{x}{4} = \\frac{x}{2} \\cdot \\frac{4}{x} = 2$"}}]},{"header":"Bruchterme vereinfachen","content":[{"markdown":"Bei Bruchtermen kürzen wir gemeinsame Faktoren im Zähler und Nenner."},{"type":"card","kind":"concept","content":{"markdown":"$\\frac{x^2 - 4}{x + 2} = \\frac{(x+2)(x-2)}{x+2} = x - 2$"}},{"type":"callout","content":{"markdown":"Vor dem Kürzen unbedingt faktorisieren. Nur gemeinsame **Faktoren** dürfen gekürzt werden, keine Summanden."}}]},{"header":"Definitionsmenge","content":[{"markdown":"Ein Bruch ist nicht definiert, wenn der Nenner null ist."},{"type":"card","kind":"highlight","content":{"markdown":"Die Definitionsmenge schließt alle Werte aus, für die der Nenner 0 wird."}},{"type":"card","kind":"concept","content":{"markdown":"$\\frac{1}{x-2}$ ist nicht definiert für $x = 2$."}}]}]}'::jsonb, '82dea26db10f9e87913f0f04fa1465b2cb4ee0fc90c94288f36f113907489319') ON CONFLICT (content_key) DO UPDATE SET page_kind = EXCLUDED.page_kind, subject_id = EXCLUDED.subject_id, topic_id = EXCLUDED.topic_id, chapter_id = EXCLUDED.chapter_id, worksheet_id = EXCLUDED.worksheet_id, title = EXCLUDED.title, source_format = EXCLUDED.source_format, source_path = EXCLUDED.source_path, content_json = EXCLUDED.content_json, content_hash = EXCLUDED.content_hash, updated_at = NOW();
INSERT INTO content_pages (content_key, page_kind, subject_id, topic_id, chapter_id, worksheet_id, title, source_format, source_path, content_json, content_hash) VALUES ('chapter:math:terme-gleichungen:potenzen-wurzeln', 'chapter', 'math', 'terme-gleichungen', 'potenzen-wurzeln', NULL, 'Potenzen und Wurzeln', 'md', 'content/base/math/terme-gleichungen/40-potenzen-wurzeln/overview.md', '{"title":"Potenzen und Wurzeln","content":[{"header":"Potenzgesetze","content":[{"type":"card","kind":"highlight","content":{"markdown":"$a^m \\cdot a^n = a^{m+n}$\n\n$\\frac{a^m}{a^n} = a^{m-n}$\n\n$(a^m)^n = a^{m \\cdot n}$\n\n$(a \\cdot b)^n = a^n \\cdot b^n$"}},{"type":"card","kind":"concept","content":{"markdown":"$x^3 \\cdot x^4 = x^7$\n\n$\\frac{x^5}{x^2} = x^3$\n\n$(x^2)^3 = x^6$"}}]},{"header":"Besondere Exponenten","content":[{"type":"card","kind":"highlight","content":{"markdown":"$a^0 = 1$ (für $a \\neq 0$)\n\n$a^{-n} = \\frac{1}{a^n}$\n\n$a^{\\frac{1}{n}} = \\sqrt[n]{a}$\n\n$a^{\\frac{m}{n}} = \\sqrt[n]{a^m}$"}},{"type":"card","kind":"concept","content":{"markdown":"$2^{-3} = \\frac{1}{8}$\n\n$8^{\\frac{1}{3}} = \\sqrt[3]{8} = 2$\n\n$4^{\\frac{3}{2}} = (\\sqrt{4})^3 = 8$"}}]},{"header":"Wurzeln","content":[{"markdown":"Eine Wurzel ist die Umkehrung des Potenzierens."},{"type":"card","kind":"highlight","content":{"markdown":"$\\sqrt{a} \\cdot \\sqrt{b} = \\sqrt{a \\cdot b}$\n\n$\\frac{\\sqrt{a}}{\\sqrt{b}} = \\sqrt{\\frac{a}{b}}$"}},{"type":"card","kind":"concept","content":{"markdown":"$\\sqrt{12} = \\sqrt{4 \\cdot 3} = 2\\sqrt{3}$\n\n$\\sqrt{50} = \\sqrt{25 \\cdot 2} = 5\\sqrt{2}$"}},{"type":"callout","content":{"markdown":"$\\sqrt{a^2} = |a|$, da die Wurzel immer nicht-negativ ist."}}]}]}'::jsonb, '588d3e26633d317bee6ebec4558233ebe3ee5ca15186d44cac5e95d3a973f503') ON CONFLICT (content_key) DO UPDATE SET page_kind = EXCLUDED.page_kind, subject_id = EXCLUDED.subject_id, topic_id = EXCLUDED.topic_id, chapter_id = EXCLUDED.chapter_id, worksheet_id = EXCLUDED.worksheet_id, title = EXCLUDED.title, source_format = EXCLUDED.source_format, source_path = EXCLUDED.source_path, content_json = EXCLUDED.content_json, content_hash = EXCLUDED.content_hash, updated_at = NOW();
INSERT INTO content_pages (content_key, page_kind, subject_id, topic_id, chapter_id, worksheet_id, title, source_format, source_path, content_json, content_hash) VALUES ('chapter:math:terme-gleichungen:gleichungen-loesen', 'chapter', 'math', 'terme-gleichungen', 'gleichungen-loesen', NULL, 'Gleichungen lösen', 'md', 'content/base/math/terme-gleichungen/50-gleichungen-loesen/overview.md', '{"title":"Gleichungen lösen","content":[{"header":"Lineare Gleichungen","content":[{"markdown":"Eine lineare Gleichung hat die Form $ax + b = 0$.\n\nWir lösen durch Äquivalenzumformungen: Auf beiden Seiten dieselbe Operation anwenden."},{"type":"card","kind":"highlight","content":{"markdown":"1. Terme zusammenfassen\n2. Variablen auf eine Seite bringen\n3. Durch den Koeffizienten dividieren"}},{"type":"card","kind":"concept","content":{"markdown":"$3x - 5 = 2x + 4$\n\n$x = 9$"}}]},{"header":"Quadratische Gleichungen","content":[{"markdown":"Eine quadratische Gleichung hat die Form $ax^2 + bx + c = 0$."},{"type":"subheader","header":{"markdown":"pq-Formel"}},{"type":"card","kind":"highlight","content":{"markdown":"$x^2 + px + q = 0$\n\n$x_{1,2} = -\\frac{p}{2} \\pm \\sqrt{\\left(\\frac{p}{2}\\right)^2 - q}$"}},{"type":"card","kind":"concept","content":{"markdown":"$x^2 - 5x + 6 = 0$\n\n$x_{1,2} = \\frac{5}{2} \\pm \\sqrt{\\frac{25}{4} - 6} = \\frac{5}{2} \\pm \\frac{1}{2}$\n\n$x_1 = 3, \\quad x_2 = 2$"}},{"type":"callout","content":{"markdown":"Ist der Ausdruck unter der Wurzel negativ, hat die Gleichung keine reelle Lösung."}}]},{"header":"Bruchgleichungen","content":[{"markdown":"Wir multiplizieren beide Seiten mit dem Hauptnenner und prüfen anschließend die Probe."},{"type":"card","kind":"concept","content":{"markdown":"$\\frac{x}{x-1} = \\frac{2}{x-1} + 1$\n\nHauptnenner: $(x-1)$\n\n$x = 2 + (x-1) \\Rightarrow x = x + 1$ — keine Lösung"}},{"type":"callout","content":{"markdown":"Nach dem Lösen immer Probe machen: Ausgeschlossene Werte können als Scheinlösung auftauchen."}}]},{"header":"Wurzelgleichungen","content":[{"markdown":"Wir quadrieren beide Seiten und prüfen anschließend die Probe."},{"type":"card","kind":"concept","content":{"markdown":"$\\sqrt{x + 3} = x - 1$\n\n$x + 3 = (x-1)^2 = x^2 - 2x + 1$\n\n$x^2 - 3x - 2 = 0 \\Rightarrow x_1 = ..., x_2 = ...$\n\nProbe einsetzen — nur Werte behalten, die die Originalgleichung erfüllen."}},{"type":"callout","content":{"markdown":"Quadrieren ist keine Äquivalenzumformung. Deshalb ist die Probe Pflicht."}}]}]}'::jsonb, 'f458c599042dfcefd4628d1b97269de8eaae03eeeffb672bb8027cb3bed552c5') ON CONFLICT (content_key) DO UPDATE SET page_kind = EXCLUDED.page_kind, subject_id = EXCLUDED.subject_id, topic_id = EXCLUDED.topic_id, chapter_id = EXCLUDED.chapter_id, worksheet_id = EXCLUDED.worksheet_id, title = EXCLUDED.title, source_format = EXCLUDED.source_format, source_path = EXCLUDED.source_path, content_json = EXCLUDED.content_json, content_hash = EXCLUDED.content_hash, updated_at = NOW();